class Solution:
    def jobScheduling(self, startTime, endTime, profit):
        jobs = sorted(zip(endTime, startTime, profit))
        n = len(jobs)
        dp = [0] * (n + 1)
        for i in range(n):
            e, s, p = jobs[i]
            best = p
            for j in range(i):
                if jobs[j][0] <= s:
                    best = max(best, dp[j + 1] + p)
            dp[i + 1] = max(dp[i], best)
        return dp[n]

